document.addEventListener("click",(t=>{const e=t.target.closest("a[data-smooth-scroll]");if(!e)return;const o=e.getAttribute("href");if(!o||!o.startsWith("#"))return;t.preventDefault();const r=document.querySelector(o);if(!r)return;const n=(parseInt(e.dataset.smoothScroll,10)||0)+("true"===e.dataset.extra?30:0),s=r.getBoundingClientRect().top+window.pageYOffset-n;window.scrollTo({top:s,behavior:"smooth"})}));